member.remarks:
Use this method to customize how the input field for this parameter is rendered when its value is requested, e.g.:
builder.AddParameter("external-service-url") .WithCustomInput(parameter => new() { InputType = parameter.Secret ? InputType.SecretText : InputType.Text, Value = "https://example.com", Label = parameter.Name, Placeholder = $"Enter value for {parameter.Name}", Description = parameter.Description });
This method is not available in polyglot app hosts.

example.code:
// Log a message with Markdown formatting
step.Log(LogLevel.Information, new MarkdownString("Deployed **myapp** to [endpoint](https://example.com)"));

// Add a Markdown-formatted value to the pipeline summary
summary.Add("Key", new MarkdownString($"[{name}]({url})"));

// In a pipeline step
context.PipelineContext.Summary.Add("☁️ Target", "Azure");
context.PipelineContext.Summary.Add("📦 Resource Group", "rg-myapp");

// In a pipeline step
context.Summary.Add("☁️ Target", "Azure");
context.Summary.Add("📦 Resource Group", "rg-myapp");

// In a pipeline step, add to the summary
public async Task ExecuteAsync(PipelineStepContext context)
{
    // Do work...

    // Add plain text summary items
    context.PipelineContext.Summary.Add("☁️ Target", "Azure");
    context.PipelineContext.Summary.Add("📦 Resource Group", "rg-myapp");
    context.PipelineContext.Summary.Add("🔑 Subscription", "12345678-1234-1234-1234-123456789012");
    context.PipelineContext.Summary.Add("🌐 Location", "eastus");
}

    // Kubernetes example
    context.PipelineContext.Summary.Add("☸️ Target", "Kubernetes");
    context.PipelineContext.Summary.Add("📦 Namespace", "production");
    context.PipelineContext.Summary.Add("🖥️ Cluster", "my-cluster");

    // Docker example
    context.PipelineContext.Summary.Add("🐳 Target", "Docker");
    context.PipelineContext.Summary.Add("🌐 Endpoint", "localhost:8080");

    // Add a Markdown-formatted value (e.g., a clickable link)
    context.PipelineContext.Summary.Add("📦 Resource Group", new MarkdownString($"[{rgName}]({portalUrl})"));

remarks.example:
Example of adding a project to the application model.

var builder = DistributedApplication.CreateBuilder(args);

builder.AddProject<Projects.InventoryService>("inventoryservice");

builder.Build().Run();

Add a project to the app model via a project path.

var builder = DistributedApplication.CreateBuilder(args);

builder.AddProject("inventoryservice", @"..\InventoryService\InventoryService.csproj");

builder.Build().Run();

Example of adding a project to the application model.

var builder = DistributedApplication.CreateBuilder(args);

builder.AddProject<Projects.InventoryService>("inventoryservice", launchProfileName: "otherLaunchProfile");

builder.Build().Run();

Add a project to the app model via a project path.

var builder = DistributedApplication.CreateBuilder(args);

builder.AddProject("inventoryservice", @"..\InventoryService\InventoryService.csproj", launchProfileName: "otherLaunchProfile");

builder.Build().Run();

Example of adding a project to the application model.

var builder = DistributedApplication.CreateBuilder(args);

builder.AddProject<Projects.InventoryService>("inventoryservice", options => { options.LaunchProfileName = "otherLaunchProfile"; });

builder.Build().Run();

Add a project to the app model via a project path.

var builder = DistributedApplication.CreateBuilder(args);

builder.AddProject("inventoryservice", @"..\InventoryService\InventoryService.csproj", options => { options.LaunchProfileName = "otherLaunchProfile"; });

builder.Build().Run();

Add a file-based app to the app model via a file path.

var builder = DistributedApplication.CreateBuilder(args);

builder.AddCSharpApp("inventoryservice", @"..\InventoryService.cs");

builder.Build().Run();

Add a file-based app to the app model via a file path.

var builder = DistributedApplication.CreateBuilder(args);

builder.AddCSharpApp("inventoryservice", @"..\InventoryService.cs", o => o.LaunchProfileName = "https");

builder.Build().Run();

Start multiple instances of the same service.

var builder = DistributedApplication.CreateBuilder(args);

builder.AddProject<Projects.InventoryService>("inventoryservice")
       .WithReplicas(3);

Disable forwarded headers for a project.

var builder = DistributedApplication.CreateBuilder(args);

builder.AddProject<Projects.InventoryService>("inventoryservice")
       .DisableForwardedHeaders();

